import{_ as t,o,c as r,a6 as a}from"./chunks/framework.Dygbm21p.js";const m=JSON.parse('{"title":"📡 3D 激光感知","description":"","frontmatter":{"custom":true,"partTitle":"3D 激光感知","partColor":null},"headers":[],"relativePath":"custom/3d-lidar.md","filePath":"custom/3d-lidar.md"}'),n={name:"custom/3d-lidar.md"};function e(i,s,d,l,c,p){return o(),r("div",null,[...s[0]||(s[0]=[a('<div class="part-hero custom-hero" style="--part-color:#14b8a6;"><h1 id="📡-3d-激光感知" tabindex="-1">📡 3D 激光感知 <a class="header-anchor" href="#📡-3d-激光感知" aria-label="Permalink to &quot;📡 3D 激光感知&quot;">​</a></h1><p class="part-desc">LiDAR · 点云 · 目标检测 · 共 1 题</p><span class="part-round custom-tag">我的题库</span></div><div class="custom-hint"><p>📝 <strong>本分类源文件</strong>：<code>custom/3d-lidar/</code> · 新增题目后运行 <code>npm run prepare</code> 即可刷新。</p></div><div class="question-card custom-card" id="lidar-vs-camera"><h2 class="question-title"><span class="q-badge custom-badge">✦</span> 点云与激光雷达基础</h2><div class="q-meta"><strong>轮次</strong>：一面 · 难度：⭐⭐⭐ · 标签：3D感知, 点云, LiDAR · 考察点：传感器原理</div><div class="question-prompt"><strong>题目</strong>：激光雷达点云和图像相比，有哪些优缺点？你在项目中是怎么用的？</div><div class="q-conclusion"><p>💡 <strong>15 秒结论</strong>：LiDAR 优点是绝对深度、不受光照影响；缺点是稀疏、贵、语义弱；融合方案通常是 LiDAR 做几何、Camera 做语义。</p></div><div class="q-followups"><p>🔁 <strong>追问方向</strong>：多传感器融合怎么做标定？ · 点云稀疏怎么补？</p></div><details class="answer-reveal"><summary>展开完整回答</summary><div class="answer-body"><p>&quot;LiDAR 的核心优势是<strong>精确的三维几何信息</strong>——每个点都有真实的 xyz 坐标和反射强度，不依赖光照，夜间和逆光也能稳定工作。缺点是点云<strong>稀疏</strong>（64 线雷达垂直分辨率有限）、<strong>无语义</strong>（不知道这个点是车还是墙）、<strong>成本高</strong>。</p><p>图像的优势是<strong>语义丰富、分辨率高、成本低</strong>，但深度是估计出来的，远距离和弱纹理区域不可靠。</p><p>在实际项目里，我通常采用<strong>优势互补的融合策略</strong>：</p><ol><li><strong>LiDAR 负责几何</strong>——地面分割、障碍物检测、距离估计</li><li><strong>Camera 负责语义</strong>——交通牌识别、车道线、目标分类</li><li><strong>融合层</strong>——用标定矩阵把点云投影到图像平面，或用 BEV 空间统一表示</li></ol><p>如果是纯 LiDAR 方案，我会先做<strong>地面滤除</strong>（RANSAC 或高度阈值），再聚类得到目标候选，最后分类器做识别。&quot;</p></div></details></div>',3)])])}const u=t(n,[["render",e]]);export{m as __pageData,u as default};
